const req = items[0].json;
const input = req.body || {};

return [
  {
    json: {
      caseId: input.testCaseId ?? "Unknown Test Case",
      status: input.status ?? "UNKNOWN",
      message: input.message ?? "",
      teststeps: input.executed_steps
        .map((step, index) => `${index + 1}. ${step}`)
        .join('\n') ?? "",
      screenshot: input.screenshot_base64 ?? "",
      timestamp: input.timestamp ?? new Date().toISOString(),
      url: input.url ?? "",

      steps: input.message 
        ? input.message.match(/Step \d+:.+/g) || [] 
        : []
    }
  }
];

const base64String = $('Parse Input').first().json.screenshot

if (base64String) {
  return [
    {
      json: $input.first().json,
      binary: {
        data: {
          data: base64String,
          mimeType: 'image/png',
          fileName: $('Parse Output AI').first().json.ticket_title.issue_title + '.png'
        }
      }
    }
  ];
}

return [$input.first()];

const data = $input.first().json;
const msg = data.message || "";

// keyword
const keywordMatch = msg.match(/Verify\w+Keyword/);
const keyword = keywordMatch ? keywordMatch[0] : "UNKNOWN";

// object repository
const repoMatch = msg.match(/Object Repository\/[^\r\n']+/);
const objectRepo = repoMatch ? repoMatch[0] : "UNKNOWN";

// xpath
const xpathMatch = msg.match(/By\.xpath:\s*(.+?)'/);
const xpath = xpathMatch ? xpathMatch[1] : "UNKNOWN";

// fingerprint
const fingerprint =
`${data.caseId}|${keyword}|${objectRepo}|${xpath}`;

return [{
  json: {
    ...data,
    fingerprint
  }
}];

