const rawOutput = $input.first().json.output; 

const cleanOutput = rawOutput.replace(/^```json\s*/i, "").replace(/^```\s*/i, "").replace(/\s*```$/, "");

let jsonData;
try {
    jsonData = JSON.parse(cleanOutput);
} catch (error) {
    jsonData = { error: "Gagal parsing JSON", raw: cleanOutput };
}

return { json: jsonData };

const targetFingerprint =
  $('Generate Fingerprint').first().json.fingerprint;

const issues = $input.all();

// Ganti customfield Error Fingerprint
const duplicates = issues.filter(item =>
  item.json.fields?.customfield_10044 === targetFingerprint
);
return duplicates.map(item => ({
  json: item.json
}));

